import '../App.js'
import '../App.css';

import React, { Component, useState } from 'react';
// import Product  from './Product.js';

function Cart({props}) {
  return (
  <>
  {
props.map((cartItem,cartIndex)=>{
   return(
      <div className='cart py-5'>
      <div className='d-flex justify-content-around align-items-center  '>
        
     <img src={cartItem.CartImg} alt="" className="w-25"/>
        <div className=''>{cartItem.CartPrice}</div>
        <div className='cart-btn d-flex gap-2'>
     <div className='cart-minus'>
     <button >-</button>
     </div>
     <p className='mb-0'>
     
     </p>
     <div className='cart-plus'>
     <button>+</button>
     
     </div>
        </div>
        <div className='buy'>
     <button>buy now</button>
        </div>
      </div>
     
     </div>
   )

})
}

</>
  );
}

export default Cart;
